// 🔹 IR A FILTROS
window.irAFiltros = function () {

  document.body.querySelectorAll("body > *").forEach(el => {
    if (el.id !== "pantallaFiltros") {
      el.style.display = "none";
    }
  });

  document.getElementById("pantallaFiltros").style.display = "block";
};


// 🔙 VOLVER
window.volver = function () {

  document.body.querySelectorAll("body > *").forEach(el => {
    el.style.display = "";
  });

  document.getElementById("pantallaFiltros").style.display = "none";
};


// 🔍 FILTRAR Y MOSTRAR
window.verResultados = function () {

  const anio = document.getElementById("filtroAnio").value;
  const calle = document.getElementById("filtroCalle").value.toLowerCase();
  const nombre = document.getElementById("filtroNombre").value.toLowerCase();
  const provincia = document.getElementById("filtroProvincia").value.toLowerCase();

  let lista = obtenerListaOrdenada();

  lista = lista.filter(p => {

    let ok = true;

    if (anio && !p.fechaNacimiento?.includes(anio)) ok = false;

    if (calle && !p.direccionCompleta?.toLowerCase().includes(calle)) ok = false;

    if (nombre && !p.nombreCompleto?.toLowerCase().includes(nombre)) ok = false;

    if (provincia && !p.provincia?.toLowerCase().includes(provincia)) ok = false;

    return ok;

  });

  pintarResultados(lista);

};


// 🖥️ MOSTRAR RESULTADOS
function pintarResultados(lista) {

  const cont = document.getElementById("resultadosFiltros");
  cont.innerHTML = "";

  if (lista.length === 0) {
    cont.innerHTML = "<p>No hay resultados</p>";
    return;
  }

  lista.forEach(p => {

    const div = document.createElement("div");
    div.className = "card";

    div.innerHTML = `
      <b>${p.nombreCompleto}</b><br>
      ${p.direccionCompleta || ""}<br>
      ${p.codigoPostal || ""} ${p.poblacion || ""}<br>
      ${p.provincia || ""}
    `;

    cont.appendChild(div);

  });

}
window.pdfFiltrado = function () {

  const anio = document.getElementById("filtroAnio").value;
  const calle = document.getElementById("filtroCalle").value;
  const nombre = document.getElementById("filtroNombre").value;
  const provincia = document.getElementById("filtroProvincia").value;

  let lista = obtenerListaOrdenada();

  lista = lista.filter(p => {

    let ok = true;

    if (anio && !p.fechaNacimiento?.includes(anio)) ok = false;
    if (calle && !p.direccionCompleta?.toLowerCase().includes(calle.toLowerCase())) ok = false;
    if (nombre && !p.nombreCompleto?.toLowerCase().includes(nombre.toLowerCase())) ok = false;
    if (provincia && !p.provincia?.toLowerCase().includes(provincia.toLowerCase())) ok = false;

    return ok;

  });

  // 🧠 construir texto filtros
  const filtrosTexto = [];

  if (anio) filtrosTexto.push("Año: " + anio);
  if (calle) filtrosTexto.push("Calle: " + calle);
  if (nombre) filtrosTexto.push("Nombre: " + nombre);
  if (provincia) filtrosTexto.push("Provincia: " + provincia);

  generarPDFListado(lista, filtrosTexto);

};
window.generarPDFListado = function (lista, filtrosTexto) {

  const { jsPDF } = window.jspdf;
  const doc = new jsPDF();

  const logoBase64 = "data:image/jpeg;base64,";
// 🎨 FONDO CABECERA
doc.setFillColor(230, 240, 255); // azul muy suave
doc.rect(0, 0, 210, 30, "F");
  let y = 18;
doc.setTextColor(0, 70, 140); // azul elegante
doc.setFontSize(18);
doc.setFont(undefined, "bold");
doc.text("COFRADÍA SAN CRISTÓBAL", 10, y);
  // 🖼️ LOGO
  doc.addImage(logoBase64, "PNG", 150, 5, 40, 20);

  // 🧾 CABECERA
  doc.setFontSize(18);
  doc.setFont(undefined, "bold");
  doc.text("COFRADÍA SAN CRISTÓBAL", 10, y);

  y += 8;

  doc.setFontSize(12);
  doc.setFont(undefined, "normal");
  doc.text("Listado de personas", 10, y);

  y += 4;
  doc.line(10, y, 200, y);

  y += 8;

  // 🔍 FILTROS
  if (filtrosTexto.length > 0) {

    doc.setFontSize(11);
    doc.setFont(undefined, "bold");
    doc.text("Filtro aplicado:", 10, y);

    y += 6;

    doc.setFont(undefined, "normal");

    filtrosTexto.forEach(f => {
      doc.text("• " + f, 12, y);
      y += 5;
    });

    y += 4;
    doc.line(10, y, 200, y);
    y += 8;
  }

  // 📊 TOTAL
  doc.setFontSize(10);
  doc.setFont(undefined, "italic");
  doc.text(`Total registros: ${lista.length}`, 10, y);

  y += 10;

  // 📋 LISTADO
  lista.forEach((p, i) => {

    if (y > 270) {
      doc.addPage();
      y = 15;
    }

    // 🔹 NOMBRE
    doc.setFontSize(11);
    doc.setFont(undefined, "bold");
    doc.text(`${i + 1}. ${p.nombreCompleto}`, 10, y);

    y += 5;

    // 🔹 DIRECCIÓN
    doc.setFontSize(10);
    doc.setFont(undefined, "normal");

    doc.text(p.direccionCompleta || "", 12, y);
    y += 5;

    doc.text(
      `${p.codigoPostal || ""} ${p.poblacion || ""} ${p.provincia || ""}`,
      12,
      y
    );

    y += 5;

    // 🎂 FECHA NACIMIENTO (NUEVO)
    if (p.fechaNacimiento) {
      doc.setFontSize(9);
      doc.setTextColor(80);
      doc.text(`Fecha nacimiento: ${p.fechaNacimiento}`, 12, y);
      doc.setTextColor(0);
      y += 5;
    }

    y += 2;

    // línea separadora
    doc.setDrawColor(200);
    doc.line(10, y, 200, y);

    y += 6;

  });

  // 📅 PIE
  const fecha = new Date().toLocaleDateString("es-ES");

  doc.setFontSize(9);
  doc.setTextColor(100);
  doc.text(`Generado el: ${fecha}`, 10, 290);

  doc.save("listado_filtrado.pdf");

};